probe = np.array([3, 4])

candidates = {
    "same_genre": np.array([6, 8]),
    "related": np.array([4, 1]),
    "orthogonal": np.array([4, -3]),
    "opposite": np.array([-3, -4]),
}

for name, vec in candidates.items():
    print(name, vec)

def dot_by_hand(a, b):
    total = 0
    for ai, bi in zip(a, b):
        total += ai * bi
    return total

scores = {name: dot_by_hand(probe, vec) for name, vec in candidates.items()}
for name, score in scores.items():
    print(name, score)

for name, vec in candidates.items():
    assert dot_by_hand(probe, vec) == np.dot(probe, vec)

print("Manual multiply-and-add matches np.dot exactly.")

probe = np.array([1.0, 3.0])
candidates = {
    "song_a": np.array([2.0, 6.0]),
    "song_b": np.array([3.0, -1.0]),
    "song_c": np.array([-2.0, -6.0]),
    "song_d": np.array([0.0, 2.0]),
}

print("probe:", probe)
for name, vec in candidates.items():
    print(name, vec)

def dot_by_hand(a, b):
    total = 0.0
    for x, y in zip(a, b):
        total += x * y
    return total

scores = {name: dot_by_hand(probe, vec) for name, vec in candidates.items()}
for name, s in scores.items():
    print(name, s)

for name, vec in candidates.items():
    assert abs(dot_by_hand(probe, vec) - np.dot(probe, vec)) < 1e-9

def rotate(v, theta):
    c, s = np.cos(theta), np.sin(theta)
    return np.array([c * v[0] - s * v[1], s * v[0] + c * v[1]])

probe_turned = rotate(probe, np.pi / 2)
scores_turned = {name: dot_by_hand(probe_turned, vec) for name, vec in candidates.items()}

print("probe was:", probe, "-> now:", probe_turned)
for name in candidates:
    print(name, "before:", scores[name], "after:", scores_turned[name])

assert any(abs(scores[name] - scores_turned[name]) > 1e-6 for name in candidates)

candidates = {
    "song_bright": np.array([4, 3]),
    "song_mellow": np.array([-3, 4]),
    "song_moody": np.array([-4, -3]),
    "song_offbeat": np.array([1, -1]),
}
probe = np.array([4, 3])

print("probe:", probe)
for name, vec in candidates.items():
    print(f"{name:14s}: {vec}")

def dot_score(a, b):
    """Multiply entry by entry, then add. That's the whole rule."""
    total = 0.0
    for x, y in zip(a, b):
        total += x * y
    return total

scores = {name: dot_score(probe, vec) for name, vec in candidates.items()}

for name, score in sorted(scores.items(), key=lambda kv: kv[1], reverse=True):
    print(f"{name:14s}: {score:+.1f}")

# cross-check the hand-rolled version against numpy's own dot
for name, vec in candidates.items():
    assert dot_score(probe, vec) == np.dot(probe, vec)

winner = max(scores, key=scores.get)
assert winner == "song_bright"
assert any(s < 0 for s in scores.values())

probe = np.array([3.0, 0.0])

candidates = {
    "A": np.array([3.0, 1.0]),
    "B": np.array([1.0, 3.0]),
    "C": np.array([-2.0, 2.0]),
    "D": np.array([-3.0, -1.0]),
}

for name, vec in candidates.items():
    print(name, vec)

def dot_by_hand(u, v):
    return sum(x * y for x, y in zip(u, v))

scores = {name: dot_by_hand(vec, probe) for name, vec in candidates.items()}
for name, score in scores.items():
    print(name, score)

# our hand-rolled version and NumPy's built-in must agree
for name, vec in candidates.items():
    assert dot_by_hand(vec, probe) == np.dot(vec, probe)

def probe_at(angle_deg, length=3.0):
    angle = np.radians(angle_deg)
    return np.array([length * np.cos(angle), length * np.sin(angle)])

for angle in [0, 45, 90, 135, 180]:
    p = probe_at(angle)
    row = {name: round(dot_by_hand(vec, p), 2) for name, vec in candidates.items()}
    print(f"angle {angle:>3} deg -> {row}")

